import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface SubscriptionMetrics {
  monthlyRecurringRevenue: {
    current: number;
    lastMonth: number;
    growthRate: number;
  };
  churnRate: number;
  newSubscriptions: number;
}

interface GrowthTrend {
  month: string;
  MRR: number;
}

interface RevenueData {
  subscriptionMetrics: SubscriptionMetrics;
  growthTrend: GrowthTrend[];
}

export default function Widget() {
  const data = response.data as RevenueData;
  const { subscriptionMetrics, growthTrend } = data;
  const isGrowthPositive = subscriptionMetrics.growthRate >= 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Monthly Recurring Revenue
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#009688' }}>
              ${subscriptionMetrics.monthlyRecurringRevenue.current.toLocaleString()}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5}>
              {isGrowthPositive ? (
                <TrendingUp sx={{ fontSize: 16, color: '#009688' }} />
              ) : (
                <TrendingDown sx={{ fontSize: 16, color: '#FF5722' }} />
              )}
              <Typography variant="body2" sx={{ color: isGrowthPositive ? '#009688' : '#FF5722' }}>
                {subscriptionMetrics.growthRate.toFixed(2)}% from last month
              </Typography>
            </Stack>
          </Box>

          <Stack direction="row" spacing={1}>
            <Chip label={`Churn Rate: ${subscriptionMetrics.churnRate}%`} sx={{ fontSize: '11px', px: 1 }} />
            <Chip label={`New Subs: ${subscriptionMetrics.newSubscriptions}`} sx={{ fontSize: '11px', px: 1 }} />
          </Stack>

          <Box sx={{ width: '100%', height: 200 }}>
            <LineChart
              height={140}
              series={[
                {
                  data: growthTrend.map((item) => item.MRR),
                  color: '#009688',
                  curve: 'linear',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: growthTrend.map((item) => item.month),
                  scaleType: 'band',
                  tickLabelStyle: { fontSize: 10, fill: '#6B7280' },
                },
              ]}
              yAxis={[
                { tickLabelStyle: { fontSize: 10, fill: '#6B7280' } },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
